#include "EmbeddingAverager.h"
#include <algorithm>
#include <cmath>
#include "../common/MathUtils.h"
namespace offlineface::inference {
std::vector<float> EmbeddingAverager::PushEmbedding(uint64_t timestampNs, const std::vector<float>& embedding) { std::lock_guard<std::mutex> lock(mutex_); if (embedding.empty()) return {}; samples_.push_back(Sample{timestampNs, embedding}); PruneWindow(timestampNs); while (samples_.size() > 5U) samples_.pop_front(); if (samples_.size() == 1U) { std::vector<float> single = samples_.front().embedding; offlineface::common::NormalizeL2(single.data(), single.size()); return single; } std::vector<float> pairwiseMean(samples_.size(), 0.0f); for (std::size_t i = 0; i < samples_.size(); ++i) { float total = 0.0f; for (std::size_t j = 0; j < samples_.size(); ++j) { if (i == j) continue; total += offlineface::common::EuclideanDistance(samples_[i].embedding.data(), samples_[j].embedding.data(), samples_[i].embedding.size()); } pairwiseMean[i] = total / static_cast<float>(samples_.size() - 1U); } float globalMean = 0.0f; for (float value : pairwiseMean) globalMean += value; globalMean /= static_cast<float>(pairwiseMean.size()); float variance = 0.0f; for (float value : pairwiseMean) { const float delta = value - globalMean; variance += delta * delta; } variance /= static_cast<float>(pairwiseMean.size()); const float stddev = std::sqrt(std::max(0.0f, variance)); const float threshold = globalMean + (1.5f * stddev); std::vector<std::vector<float>> accepted; accepted.reserve(samples_.size()); for (std::size_t index = 0; index < samples_.size(); ++index) if (pairwiseMean[index] <= threshold || accepted.empty()) accepted.push_back(samples_[index].embedding); std::vector<float> centroid = offlineface::common::ComputeCentroid(accepted); offlineface::common::NormalizeL2(centroid.data(), centroid.size()); return centroid; }
void EmbeddingAverager::PruneWindow(uint64_t latestTimestampNs) { constexpr uint64_t kWindowNs = 500000000ULL; while (!samples_.empty() && latestTimestampNs > samples_.front().timestampNs && (latestTimestampNs - samples_.front().timestampNs) > kWindowNs) samples_.pop_front(); }
}
